// Pull the 3 Claude outputs and assemble a Ghost-compatible post payload.
// Claude returns content as { content: [{ type: 'text', text: '...' }] } —
// outline + SEO are JSON strings, draft is HTML.

const startTs = $('Webhook (form submit)').item.json.body.startTs || Date.now();

function extractText(node) {
  const data = $(node).item.json;
  if (data && Array.isArray(data.content) && data.content[0] && typeof data.content[0].text === 'string') {
    return data.content[0].text;
  }
  throw new Error(`Could not extract text from ${node}`);
}

function safeParseJson(raw, label) {
  const trimmed = raw.trim();
  // Tolerate accidental code fences
  const cleaned = trimmed.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  try {
    return JSON.parse(cleaned);
  } catch (e) {
    throw new Error(`Failed to parse ${label} JSON: ${e.message}`);
  }
}

const outline = safeParseJson(extractText('Claude — Research & Outline'), 'outline');
const html = extractText('Claude — Full Draft').trim();
const seo = safeParseJson(extractText('Claude — SEO Meta'), 'seo');

// Ghost expects tags as an array of { name } or comma-separated string.
// We'll send an array of strings; the Ghost node accepts that.
const tags = Array.isArray(seo.focusKeywords) ? seo.focusKeywords.slice(0, 5) : [];
const excerpt = (seo.metaDescription || '').slice(0, 200);

// Final payload for the Ghost node
return [{
  json: {
    title: outline.title,
    targetAudience: outline.targetAudience,
    html,
    metaTitle: seo.metaTitle,
    metaDescription: seo.metaDescription,
    slug: seo.slug,
    focusKeywords: tags,
    tags: tags.join(', '),
    excerpt,
    startTs,
  },
}];
